"use client";
import * as React from "react";
import { spinnerAnatomy } from "@tessera/core";

export interface SpinnerProps extends React.HTMLAttributes<HTMLSpanElement> {
  size?: "sm" | "md" | "lg";
  /** Accessible label announced to screen readers. Default "Loading". */
  label?: string;
}

export const Spinner = React.forwardRef<HTMLSpanElement, SpinnerProps>(function Spinner(
  { size = "md", label = "Loading", ...rest },
  ref
) {
  return (
    <span
      {...spinnerAnatomy.attrs("root")}
      data-size={size}
      role="status"
      aria-label={label}
      ref={ref}
      {...rest}
    />
  );
});

@layer tessera.recipes {
  [data-scope="spinner"][data-part="root"] {
    --spinner-size: 1.25rem;

    display: inline-block;
    width: var(--spinner-size);
    height: var(--spinner-size);
    border-radius: var(--ts-radius-full);
    border: 2px solid var(--ts-border-muted);
    border-top-color: var(--ts-accent-default);
    animation: tessera-spin 0.7s linear infinite;
    flex-shrink: 0;
  }

  [data-scope="spinner"][data-part="root"][data-size="sm"] {
    --spinner-size: 0.875rem;
  }

  [data-scope="spinner"][data-part="root"][data-size="lg"] {
    --spinner-size: 2rem;
    border-width: 3px;
  }
}
